/* kmeans_cuda.cu */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <sys/types.h>
#include <fcntl.h>
#include <omp.h> // For wtime
#include "getopt.h"

#include "kmeans.h"

// Forward declarations for CUDA kernels
void kmeans_cuda_kernel(int numObjects, int numAttributes, float *attributes, int nclusters, float threshold, float *cluster_centres, int *membership);
void kmeans_cuda_init(int numObjects, int numAttributes, float *attributes, int nclusters, float threshold, float *cluster_centres, int *membership);

extern double wtime(void);

int num_omp_threads = 1; // This will be ignored in CUDA, but kept for signature compatibility

/*---< usage() >------------------------------------------------------------*/
void usage(char *argv0) {
    char *help =
        "Usage: %s [switches] -i filename\n"
        "       -i filename             : file containing data to be clustered\n"
        "       -b                      : input file is in binary format\n"
        "       -k                      : number of clusters (default is 5) \n"
        "       -t threshold            : threshold value\n"
        "       -n no. of threads       : number of threads (ignored for CUDA)";
    fprintf(stderr, help, argv0);
    exit(-1);
}

/*---< main() >-------------------------------------------------------------*/
int main(int argc, char **argv) {
    int     opt;
    extern char   *optarg;
    extern int     optind;
    int     nclusters = 5;
    char   *filename = 0;
    float  *attributes_h = NULL; // Host data
    float  *cluster_centres_h = NULL; // Host cluster centers
    int    *membership_h = NULL; // Host membership
    float  *attributes_d = NULL; // Device data
    float  *cluster_centres_d = NULL; // Device cluster centers
    int    *membership_d = NULL; // Device membership
    int     i, j;

    int     numAttributes = 0;
    int     numObjects = 0;
    char    line[1024];
    int     isBinaryFile = 0;
    int     nloops = 1;
    float   threshold = 0.001;
    double  timing;

    while ((opt = getopt(argc, argv, "i:k:t:b:n:?")) != EOF) {
        switch (opt) {
            case 'i': filename = optarg;
                break;
            case 'b': isBinaryFile = 1;
                break;
            case 't': threshold = atof(optarg);
                break;
            case 'k': nclusters = atoi(optarg);
                break;
            case 'n': num_omp_threads = atoi(optarg); // Ignored for CUDA
                break;
            case '?': usage(argv[0]);
                break;
            default: usage(argv[0]);
                break;
        }
    }

    if (filename == 0) usage(argv[0]);

    // --- Data Loading ---
    if (isBinaryFile) {
        int infile;
        if ((infile = open(filename, O_RDONLY, "0600")) == -1) {
            fprintf(stderr, "Error: no such file (%s)\n", filename);
            exit(1);
        }
        read(infile, &numObjects, sizeof(int));
        read(infile, &numAttributes, sizeof(int));

        // Allocate host memory
        attributes_h = (float*) malloc(numObjects * numAttributes * sizeof(float));
        membership_h = (int*) malloc(numObjects * sizeof(int));
        cluster_centres_h = (float*) malloc(nclusters * numAttributes * sizeof(float));

        if (!attributes_h || !membership_h || !cluster_centres_h) {
            fprintf(stderr, "Error: Host memory allocation failed.\n");
            exit(1);
        }

        read(infile, attributes_h, numObjects * numAttributes * sizeof(float));
        close(infile);
    } else {
        FILE *infile;
        if ((infile = fopen(filename, "r")) == NULL) {
            fprintf(stderr, "Error: no such file (%s)\n", filename);
            exit(1);
        }

        // Count objects and attributes
        while (fgets(line, 1024, infile) != NULL) {
            if (strtok(line, " \t\n") != 0) {
                numObjects++;
                // Count attributes for the first valid line
                if (numAttributes == 0) {
                    while (strtok(NULL, " ,\t\n") != NULL) numAttributes++;
                }
            }
        }
        rewind(infile);

        // Allocate host memory
        attributes_h = (float*) malloc(numObjects * numAttributes * sizeof(float));
        membership_h = (int*) malloc(numObjects * sizeof(int));
        cluster_centres_h = (float*) malloc(nclusters * numAttributes * sizeof(float));

        if (!attributes_h || !membership_h || !cluster_centres_h) {
            fprintf(stderr, "Error: Host memory allocation failed.\n");
            exit(1);
        }

        // Read attributes
        int obj_idx = 0;
        while (fgets(line, 1024, infile) != NULL) {
            char *token = strtok(line, " \t\n");
            if (token == NULL) continue;

            for (int attr_idx = 0; attr_idx < numAttributes; attr_idx++) {
                token = strtok(NULL, " ,\t\n");
                if (token == NULL) {
                    fprintf(stderr, "Error: Inconsistent number of attributes in file.\n");
                    exit(1);
                }
                attributes_h[obj_idx * numAttributes + attr_idx] = atof(token);
            }
            obj_idx++;
        }
        fclose(infile);
    }
    printf("I/O completed\n");

    // --- CUDA Initialization ---
    // Allocate device memory
    size_t data_size = numObjects * numAttributes * sizeof(float);
    size_t centres_size = nclusters * numAttributes * sizeof(float);
    size_t membership_size = numObjects * sizeof(int);

    cudaMalloc((void**)&attributes_d, data_size);
    cudaMalloc((void**)&cluster_centres_d, centres_size);
    cudaMalloc((void**)&membership_d, membership_size);

    // Copy data from host to device
    cudaMemcpy(attributes_d, attributes_h, data_size, cudaMemcpyHostToDevice);

    // --- K-Means Clustering ---
    timing = omp_get_wtime(); // Using omp_get_wtime for consistency with original code

    // Initialize cluster centers on the device (randomly pick first k points)
    kmeans_cuda_init(numObjects, numAttributes, attributes_d, nclusters, threshold, cluster_centres_d, membership_d);

    // Perform K-means iterations on the device
    // The original code had a loop for nloops, but here we'll just run it once.
    // The convergence is handled within the kernel.
    kmeans_cuda_kernel(numObjects, numAttributes, attributes_d, nclusters, threshold, cluster_centres_d, membership_d);

    // Copy results back from device to host
    cudaMemcpy(cluster_centres_h, cluster_centres_d, centres_size, cudaMemcpyDeviceToHost);
    cudaMemcpy(membership_h, membership_d, membership_size, cudaMemcpyDeviceToHost);

    timing = omp_get_wtime() - timing;

    printf("number of Clusters %d\n", nclusters);
    printf("number of Attributes %d\n\n", numAttributes);
    /*
    printf("Cluster Centers Output\n");
    printf("The first number is cluster number and the following data is arribute value\n");
    printf("=============================================================================\n\n");

    for (i = 0; i < nclusters; i++) {
        printf("%d: ", i);
        for (j = 0; j < numAttributes; j++)
            printf("%.2f ", cluster_centres_h[i * numAttributes + j]);
        printf("\n\n");
    }
    */
    printf("Time for process: %f\n", timing);

    // Free host and device memory
    free(attributes_h);
    free(membership_h);
    free(cluster_centres_h);
    cudaFree(attributes_d);
    cudaFree(cluster_centres_d);
    cudaFree(membership_d);

    return (0);
}
